                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 800, fontSize: 16 }}>{v.placa}</div>
                  <div style={{ fontSize: 12, color: C.muted }}>{v.modelo}</div>
                </div>
                <Badge color={estadoColor[v.estado] || C.muted}>
